import {
  AbsoluteFill,
  Img,
  staticFile,
  useCurrentFrame,
  useVideoConfig,
  interpolate,
} from "remotion";
import { BRAND } from "../../data";

const SERVICES = [
  { icon: "🏠", text: "Full Property Management" },
  { icon: "🔍", text: "Tenant Find & Vetting" },
  { icon: "💷", text: "Guaranteed Rent Schemes" },
  { icon: "🔧", text: "Maintenance Coordination" },
  { icon: "📋", text: "Regulatory Compliance" },
];

export const PMSolutionScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Background image — generated by WaveSpeed, falls back to solid colour
  const hasBg = true;

  const bgOpacity = interpolate(frame, [0, 0.8 * fps], [0, 1], {
    extrapolateRight: "clamp",
  });

  const logoOpacity = interpolate(frame, [0, 0.5 * fps], [0, 0.9], {
    extrapolateRight: "clamp",
  });

  const headlineOpacity = interpolate(frame, [0.3 * fps, 1.0 * fps], [0, 1], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
  });

  const headlineY = interpolate(frame, [0.3 * fps, 1.0 * fps], [40, 0], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
  });

  const lineWidth = interpolate(frame, [0.8 * fps, 1.6 * fps], [0, 500], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
  });

  return (
    <AbsoluteFill style={{ backgroundColor: BRAND.darkNavy }}>
      {/* AI-generated background */}
      <AbsoluteFill style={{ opacity: bgOpacity * 0.35 }}>
        <Img
          src={staticFile("pm-solution-bg.jpg")}
          style={{ width: "100%", height: "100%", objectFit: "cover" }}
        />
      </AbsoluteFill>

      {/* Navy overlay */}
      <AbsoluteFill
        style={{
          background: `linear-gradient(
            160deg,
            rgba(26,38,52,0.92) 0%,
            rgba(26,38,52,0.75) 50%,
            rgba(26,38,52,0.95) 100%
          )`,
        }}
      />

      {/* Logo */}
      <div
        style={{
          position: "absolute",
          top: 60,
          right: 40,
          opacity: logoOpacity,
        }}
      >
        <Img src={staticFile("logo.png")} style={{ width: 180, objectFit: "contain" }} />
      </div>

      {/* Content */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          padding: "0 55px",
        }}
      >
        {/* Headline */}
        <div
          style={{
            opacity: headlineOpacity,
            transform: `translateY(${headlineY}px)`,
            marginBottom: 16,
          }}
        >
          <div
            style={{
              color: BRAND.gold,
              fontSize: 24,
              fontWeight: 700,
              letterSpacing: 5,
              textTransform: "uppercase",
              marginBottom: 18,
            }}
          >
            The Solution
          </div>
          <div
            style={{
              color: BRAND.white,
              fontSize: 74,
              fontWeight: 900,
              lineHeight: 1.0,
              marginBottom: 6,
            }}
          >
            SJB handles
          </div>
          <div
            style={{
              color: BRAND.gold,
              fontSize: 78,
              fontWeight: 900,
              lineHeight: 1.0,
            }}
          >
            everything.
          </div>
        </div>

        {/* Gold divider */}
        <div
          style={{
            width: lineWidth,
            height: 3,
            backgroundColor: BRAND.gold,
            marginBottom: 40,
            marginTop: 30,
          }}
        />

        {/* Services list */}
        <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
          {SERVICES.map((service, i) => {
            const delay = 1.2 + i * 0.3;
            const itemOpacity = interpolate(
              frame,
              [delay * fps, (delay + 0.4) * fps],
              [0, 1],
              { extrapolateRight: "clamp", extrapolateLeft: "clamp" }
            );
            const itemX = interpolate(
              frame,
              [delay * fps, (delay + 0.4) * fps],
              [40, 0],
              { extrapolateRight: "clamp", extrapolateLeft: "clamp" }
            );

            return (
              <div
                key={service.text}
                style={{
                  opacity: itemOpacity,
                  transform: `translateX(${itemX}px)`,
                  display: "flex",
                  alignItems: "center",
                  gap: 18,
                }}
              >
                {/* Gold tick */}
                <div
                  style={{
                    width: 36,
                    height: 36,
                    borderRadius: "50%",
                    backgroundColor: BRAND.gold,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    flexShrink: 0,
                  }}
                >
                  <span style={{ fontSize: 18, color: BRAND.darkNavy, fontWeight: 900 }}>✓</span>
                </div>
                <div
                  style={{
                    color: BRAND.cream,
                    fontSize: 32,
                    fontWeight: 600,
                  }}
                >
                  {service.text}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </AbsoluteFill>
  );
};
